{
  "_comment": "@metaharness/example-web3 — MCP policy. default-deny. Mutations require --allow-mutations flag and are NOT granted here.",
  "defaultDeny": true,
  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 30000,
  "maxToolCallsPerTurn": 8,
  "auditLog": true,
  "audit_log_path": ".harness/audit/mcp-audit.jsonl",
  "mutations_require_flag": "--allow-mutations",
  "grantedTools": [
    {
      "name": "web3.eth_call",
      "description": "Read-only contract call via eth_call (no state change, no gas spent)",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    },
    {
      "name": "web3.eth_getBalance",
      "description": "Retrieve the native-token balance of an address at a given block",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    },
    {
      "name": "web3.eth_getCode",
      "description": "Fetch the deployed bytecode of a contract address",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    },
    {
      "name": "web3.eth_getLogs",
      "description": "Query historical event logs matching a filter (read-only)",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    },
    {
      "name": "web3.eth_blockNumber",
      "description": "Return the current canonical head block number",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    },
    {
      "name": "web3.eth_getTransactionReceipt",
      "description": "Fetch the receipt of a confirmed transaction (read-only)",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    },
    {
      "name": "web3.simulateTransaction",
      "description": "Dry-run a transaction via eth_call or a fork-simulation endpoint — no broadcast, no chain state change",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    },
    {
      "name": "web3.decodeAbi",
      "description": "Decode ABI-encoded calldata or return data without any RPC call",
      "needs": { "network": false, "shell": false, "fileWrite": false },
      "dangerous": false
    }
  ],
  "deniedTools": [
    {
      "name": "web3.eth_sendRawTransaction",
      "reason": "Broadcasts signed transactions — mutation. Requires --allow-mutations."
    },
    {
      "name": "web3.eth_sendTransaction",
      "reason": "Sends a transaction — mutation. Requires --allow-mutations."
    },
    {
      "name": "web3.signTransaction",
      "reason": "Signs with a private key — secret access + mutation prerequisite. Requires --allow-mutations."
    },
    {
      "name": "web3.deployContract",
      "reason": "Deploys contract bytecode — mutation. Requires --allow-mutations."
    }
  ]
}
